    _withDisposeLock(() {
      if (_disposed) return;
      _disposed = true;

      _performCleanupCore();
      _imageWidgetSize = null;
      _lastToggle = null;
      // Set enabled to false BEFORE calling onDisabled, consistent with _disableWithCleanup().
